var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……노엘 라이트.","JPN":"……ノエル・ライト。","ENG":"...Noelle Wright.","TWN":"……洛艾兒·萊特。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이전에 봤을 때보다 몸놀림이 빠르고 가볍군요.","JPN":"以前会った時よりも身のこなしが軽く、素早くなりましたね。","ENG":"You seem more nimble than the last time I saw you.","TWN":"你看起來比上次見面時靈活多了。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뿐만이 아니라, 다른 두 사람과도 호흡이 제법 나쁘지 않아요.","JPN":"それだけではない。他の二人ともかなり上手く息を合わせている。","ENG":"It's not just that, your chemistry with those two has gotten better.","TWN":"不僅如此，和其他兩個人的配合也相當不錯。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"틀림없이 건틀렛 리그라는 무대를 통해, 한 단계 더 성장한 거겠죠.","JPN":"ガントレットリーグという舞台を通して、一段と成長したのでしょう。","ENG":"I'm certain that through the Gauntlet league, you've reached new heights.","TWN":"毫無疑問，透過聖鎧聯賽這個舞台，你又成長了一步。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 이런 곳에서, 이런 식으로 마주치게 될 줄은 몰랐지만…….","JPN":"そう。こんな場所で、こんな風に再会するとは思いませんでしたが……","ENG":"Yes. I didn't expect to meet you like this here, but...","TWN":"是啊，沒想到會在這種地方，以這種方式遇見……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자, 그럼 상황을 지켜보도록 할까요?","JPN":"さて、では状況を見守るとしましょうか。","ENG":"Now, shall I observe what will happen next?","TWN":"那麼，我對接下來的劇情拭目以待……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"잠깐! 장난은 거기까지다!","JPN":"待った！　お遊びはここまでだ！","ENG":"Hold it right there! Playtime's over!","TWN":"想得美！遊戲結束了！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……윽!","JPN":"……うっ！","ENG":"...Ngh!","TWN":"……唔！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 저자는……?","JPN":"ん？　あの者は……？","ENG":"Hmm? That's...?","TWN":"嗯？他是……？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"후우, 생포하는 데 고생 좀 했지. 늙다리 주제에 주먹은 더럽게 매워 가지곤.","JPN":"ふう、生け捕りするのにちょっと苦労したぜ。老いぼれのくせに拳がやたら強くてな。","ENG":"Phew. Took longer than expected to capture him alive. He's got one mean punch for an old man.","TWN":"呼，費了一番勁才活捉到他，這老傢伙拳頭很硬呢！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"자, 아무튼 분위기 파악했으면 당장 수송기에서 떨어져.","JPN":"さあ、とにかく空気読んだなら、今すぐ輸送船から離れるんだ。","ENG":"Now, step away from the aircraft if you know what's good for you.","TWN":"總之，勸你們搞清楚狀況，趕快從運輸機上下來。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그렇지 않으면 이 노인네의……","JPN":"じゃないと、この老人の……","ENG":"Or else, this old man is gonna–","TWN":"否則這個老傢伙……"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"으악! 무, 무슨 짓거리야! 아프잖아!","JPN":"うわっ！　な、何しやがる！　痛いじゃねえか！","ENG":"Aaargh! W-what was that for?! That hurt!","TWN":"呃啊！你，你做什麼！很痛欸！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시끄러워. 얼굴도 모르는 할배 데려다 놓고 어딜 개수작이야.","JPN":"うるさい。顔も知らないジジイ連れてきて、ふざけんなよ。","ENG":"Shut up. We don't even know that geezer. What are you trying to pull?","TWN":"吵死了你！我又不認識那個阿公，你把他帶來要做什麼？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"뭐? 이 노인네가 죽어도 상관없다는 거냐!?","JPN":"なにっ？　この老人が死んでもいいのか！？","ENG":"What? Then you're okay with me killing this old man?!","TWN":"什麼？我殺了他你也不在意嗎！？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"상관 있는 건 보험사겠지. 그 할배가 니들이랑 한통속인지 우리가 어떻게 알아?","JPN":"困るのは保険会社だろ？　そのジジイがあんたらとグルじゃないとどうしてわかる？","ENG":"The only ones not okay will be his insurance company. And who knows? Maybe he's on the same team as you.","TWN":"會在意的應該是保險公司吧？誰知道那個阿公是不是跟你們同一夥的？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"뭐 저런 개망나니가 다 있어!?","JPN":"何だと、この不良娘が！？","ENG":"You can't be serious right now!","TWN":"你是哪來的小王八蛋！？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치, 접선인이라는 사람이 혹시 저 할아버지에요?","JPN":"コーチ、受渡人というのはもしかしてあのお爺さんですか？","ENG":"Coach, this contact you were talking about. Is that him?","TWN":"教練，接應的人就是那個阿公嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……아닌 것 같네만?","JPN":"……違うと思うが。","ENG":"...I don't think so.","TWN":"……感覺應該不是？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카. 모르는 사람이래요, 쏴요.","JPN":"ライカ、知らない人だって。撃って。","ENG":"Laika. Coach doesn't know him. Shoot him.","TWN":"萊卡，開槍，他是陌生人。"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"아악! 내 눈!!","JPN":"ぐわっ！　俺の目！！","ENG":"Aaagh! My eye!!","TWN":"啊啊！我的眼睛！！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이런 빌어먹을! 그만 좀 쏴!","JPN":"ちくしょう！　もうやめろ！","ENG":"Dammit! Stop shooting me!","TWN":"該死的！別再開啦！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"거기 당신! 당신이 이 쇳덩이를 수리해 달라고 의뢰한 거 아닌가?","JPN":"そこのお前さん！　お前さんがこの鉄の塊の修理を依頼したんだろ？","ENG":"Hey, you! Aren't you the one who requested this hunk of metal be repaired?","TWN":"就是你！是你委託我修理這塊廢鐵的不是嗎？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"내가 이 수송기를 수리한 사람이야! 내 머리에 바람 구멍 냈다간 시동 걸 생각 말게!","JPN":"ワシがこの輸送船を修理した者だ！　ワシの頭に風穴が開いたら船は動かんぞ！","ENG":"I'm the guy who fixed her up! So don't you dare think about starting her engine when there's a hole between my eyes!","TWN":"我是修理這台運輸機的人！要是我的頭被打破洞，你就別想啟動它！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐야, 하청의 하청이라고?","JPN":"なんだ、下請けの下請け？","ENG":"What? A subcontract?","TWN":"什麼？是別人外包給你的？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"수작 부리지 마. 접선인이란 녀석은 어디 있는데?","JPN":"ふざけんなよ。接触する人って奴はどこにいるんだ？","ENG":"Like that's gonna fool anyone. So where's this contact of yours?","TWN":"少跟我來這套！那個接應的人在哪裡？"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"내가 묻고 싶은 말이다! 사람을 납치하듯이 끌고 와서는……!","JPN":"それはワシのセリフだ！　人をさらうように連れてきやがって……！","ENG":"I could ask you the same thing! I was just kidnapped and–!","TWN":"我才想問咧！把人綁來這裡……！"},"stage":{"bg":"NEWTOWN","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"누, 누구야? 어떤 놈이 지시도 안 받고 폭탄을 터뜨렸어?","JPN":"だ、誰だ？　指示もないのに誰が爆弾を爆発させた？","ENG":"W-who was that? Who blew the charge without my orders?","TWN":"是誰？哪個傢伙不聽指令亂引爆炸彈？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_QM","text":{"KOREA":"괜찮습니다. 당신 지시는 입력해도 오류만 뱉을 거거든요.","JPN":"大丈夫です。あなたの指示は入力してもエラーを吐くだけですから。","ENG":"It's all right. Your orders will only come out as errors anyway.","TWN":"沒差，就算你輸入指令也只會出現錯誤。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"으, 으응?","JPN":"あ、ああ？","ENG":"S-say what?","TWN":"呃嗯？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_QM","text":{"KOREA":"코핀 컴퍼니 사장님 맞으시죠?","JPN":"コフィンカンパニーの社長ですね？","ENG":"Coffin Company's boss, I presume?","TWN":"你是科芬公司的老闆吧？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가…… 초원 양인가? 전달 받은 자료와 조금 달라 보이는데?","JPN":"君が……ナオ君か？　もらった資料とは少し違って見えるが。","ENG":"You're... Chowon? You look different from the records that I received.","TWN":"你是…… 初源？怎麼和我收到的資料看起來不太一樣？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"회장님께서 가급적 조용히 해결해 달라고 하셨으니까요.","JPN":"会長から、できるだけ目立たずに解決するように言われておりますので。","ENG":"The President asked to handle this as silently as possible.","TWN":"會長請我盡量低調處理。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"클리포트 게임 이후로 그룹 전체가 조사를 받고 있습니다.","JPN":"クリフォトゲーム以後、グループ全体が調査を受けています。","ENG":"The entire group is under investigation after the Qliphoth Game.","TWN":"因為逆卡巴拉遊戲之後，整個集團都在接受調查。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"뭐, 회장님은 무척 잘나신 분이라 그다지 걱정은 되지 않습니다만.","JPN":"まあ、会長はとても優秀な方なので、それほど心配はありませんが。","ENG":"The President is very talented, so I'm not worried about her at all.","TWN":"不過會長是個能力非常好的人，應該沒什麼好擔心的。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"소속이 뻔히 보이는 제복을 입고 와서 새로운 문제를 만들 필요는 없겠죠.","JPN":"どこの所属か丸わかりの制服を着て、新たな問題を作る必要はないでしょう。","ENG":"However, there is no need to create new problems by wearing a uniform of my affiliation.","TWN":"要是穿著顯眼的制服出現反而會引起騷動，何必呢？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"큭…! 이 자식들이! 감히 날 무시해!?","JPN":"くっ……！　このやろう！　俺を無視するのか！！","ENG":"Kgh...! You bastards! How dare you ignore me?!","TWN":"可惡…！你們這些傢伙！竟敢小看我！？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"여기는 감마! 문제가 생겼다! 지금 즉시 지원을 요청한다!","JPN":"こちら、ガンマ！　問題が発生した！　ただちに応援を要請する！","ENG":"This is Gamma! We got a problem here! I need immediate backup!","TWN":"我是伽馬！出了點問題！現在立刻派支援過來！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여기는 감마! 문제가 생겼다! 지금 즉시 지원을 요청한다!</color>","JPN":"<color=#ffd34c>こちら、ガンマ！　問題が発生した！　ただちに応援を要請する！</color>","ENG":"<color=#ffd34c>This is Gamma! We got a problem here! I need immediate backup!</color>","TWN":"<color=#ffd34c>我是伽馬！出了點問題！現在立刻派支援過來！</color>"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"자, 잠깐? 어째서 네가…… 우리 무전기를……?","JPN":"ま、待てよ？　なんでお前が……俺らの無線機を……？","ENG":"W-what? How do you... have our comms...?","TWN":"什，什麼？你怎麼會……我們的無線電……？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"매복하고 있던 당신 동료들부터 정리하고 오느라 조금 늦어졌거든요.","JPN":"待ち伏せしていたあなたの仲間たちから処理して来たので、少々遅れました。","ENG":"It took me a while to arrive because I was busy taking care of your backup waiting to ambush us.","TWN":"我來的路上順便處理了一下你那些埋伏的夥伴，所以才會遲到。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"이제 남은 건 당신뿐이에요.","JPN":"残ったのはあなただけです。","ENG":"Now you're the only one left.","TWN":"現在只剩你還沒處理。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그, 그럼 그 거미 문양…… 설마……!","JPN":"じゃ、じゃあ、そのクモの模様……まさか……！","ENG":"Th-then that spider mark... It can't be...!","TWN":"那，那個蜘蛛的圖案……難道你……！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"가, 가가, 가까이 오지 마! 다가오면 죽여 버리겠어!!","JPN":"く、くく、来るな！　こっちに来れば殺す！！","ENG":"S-s-stay away from me! Come any closer and I'll kill him!!","TWN":"走…走開…不要過來！再過來我就殺了你！！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"걱정 마세요. 저에겐 딱히 사람을 괴롭히는 취미가 없습니다.","JPN":"心配しないでください。私は別に人をいじめる趣味は持っていません。","ENG":"Don't worry. I don't take pleasure in torturing people.","TWN":"放心，我喜歡速戰速決。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그러니 얌전히 무기를 버리고 항복하세요.","JPN":"ですので、大人しく武器を捨てて降参してください。","ENG":"So throw down your weapon and surrender.","TWN":"你只要棄械投降，我就不會為難你。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"하으으으…… 아파라.","JPN":"いたたた……","ENG":"Oof... That hurt.","TWN":"哈呃呃……好痛。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"형님, 이제 어떡합니까? 클라이언트한텐 뭐라고 설명하죠?","JPN":"兄貴、どうします？　クライアントにはなんて説明すれば……","ENG":"What do we do now, boss? What do we tell the client?","TWN":"大哥，現在怎麼辦？我們該怎麼跟客戶解釋啊？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"어떡하긴 뭘 어떡해, 임마? 이 바닥 몰라?","JPN":"どうするって、どうも何もあるか！","ENG":"What do you mean, \\"What do we do now?\\" Don't you already know how this plays out?","TWN":"怎麼辦？還能怎麼辦？你不懂這行嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"실패하면 블랙 네트워크 비공개로 돌려놓고 몇 개월 잠수 타는 거지, 뭐.","JPN":"失敗したらブラックネットワークを非公開にして、数ヶ月隠れていればいいんだよ。","ENG":"If we fail, we get rid of ourselves from the Dark Network and lay low for a couple of months.","TWN":"失敗的話就從黑色網路匿了，現實裡潛伏幾個月就行了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"젠장할, 살다 살다 거미 부대의 생존자를 보게 될 줄이야.","JPN":"ったく、まさかクモ部隊の生き残りに出くわすとはな。","ENG":"Dammit. I never imagined I'd see a former member of the Arachnid.","TWN":"該死的，活了這麼久，竟然還能見到蜘蛛的倖存者。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"급한 의뢰라고 해서 선수금이라도 챙겨서 망정이지. 큰일 날 뻔했잖아?","JPN":"急な依頼だからって、一部先払いしてもらってよかったよ。大変なことになるところだった。","ENG":"Thank god we got the payment in advance due to this job being an urgent one. That was a close one.","TWN":"幸好是緊急委託，提前拿到了定金。不然可就糟了……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"그 거미 부대라는 게 그렇게나 대단한 녀석들입니까?","JPN":"そのクモ部隊って、そんなにすごいやつらなんですか？","ENG":"Are these Arachnid people that strong?","TWN":"那群叫蜘蛛的人真有那麼厲害嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"형님 아까 완전 쫄던데요?","JPN":"兄貴、さっきめっちゃビビってましたよね。","ENG":"You were about to pee your pants, boss.","TWN":"大哥，你不會嚇得尿褲子了吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"시끄러, 네가 몰라서 그래.","JPN":"お前は知らねえからそんなことが言えるんだよ。","ENG":"Shut it, that's only because you don't know.","TWN":"吵死了，才不是這樣的好嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"<color=#ffd34c>거미</color>는 오래전에 로터스에서 알아주던 용병 부대야.","JPN":"<color=#ffd34c>クモ</color>は、昔ロータスで有名だった傭兵部隊だ。","ENG":"<color=#ffd34c>The Arachnid</color> is a famous mercenary squad from way back in Lotus.","TWN":"<color=#ffd34c>蜘蛛</color>是很久以前在洛德斯有名的傭兵部隊。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"살인, 방화, 납치, 무허가 다이브, 아티팩트 밀매 그 외 기타 등등…….","JPN":"殺人、放火、拉致、無許可ダイブ、アーティファクトの密売などなど……","ENG":"Murder, arson, kidnappings, unauthorized dives, Artifact smugglings, you name it...","TWN":"謀殺、縱火、綁架、非法潛入、走私生氣等等……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"말이 용병이지, 로터스 출신답게 온갖 미친 짓이란 미친 짓은 다 저지르고 다니던 녀석들이었지.","JPN":"傭兵とは名ばかりで、ロータス出身だけにあらゆる奇行に手を染めていた。","ENG":"They were called mercenaries, but as expected from Lotus, they were a group of people who did all things crazy.","TWN":"雖然說是雇傭兵，但畢竟出身於洛德斯，他們裡面哪個不是幹盡了各種瘋狂的事。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"그러고 보니, 로터스 출신 녀석들은 부대명이나 콜사인을 곤충 이름으로 짓던 게…….","JPN":"そういえば、ロータス出身のやつらが部隊の名前とかコールサインを昆虫の名前にしてるのって……","ENG":"Come to think of it, all the mercenaries from Lotus had their unit names or code names after insects...","TWN":"這麼說來，洛德斯出身的傢伙們總是喜歡用昆蟲的名字來命名部隊和代號……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그래, 그게 다 거미 녀석들의 위상이라고 할 수 있지.","JPN":"ああ、全部クモのやつらから影響を受けてるんだ。","ENG":"Yeah. That all started with the Arachnids.","TWN":"是啊，都是從蜘蛛的那些傢伙開始的風氣吧。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"하지만 그것도 다 옛말이야.","JPN":"しかし全部昔の話さ。","ENG":"But it's all a thing of the past.","TWN":"但那也是過去的事了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"거미는 내부분열로 자기들끼리 잡아먹다가 결국 와해되어 버렸으니까.","JPN":"クモは結局、内部で揉めて解散しちまったんだからな。","ENG":"The Arachnids had an internal dispute which eventually led to their disbanding.","TWN":"蜘蛛因為內部糾紛互相殘殺，最終四分五裂了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"너도 스캐빈저는 들어봤지?","JPN":"お前もスカベンジャーは知ってるだろ？","ENG":"You heard of Scavengers, right?","TWN":"你也聽說過清道夫吧？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"거미 녀석들이 흩어진 뒤, 배신한 조직원 대다수가 신체 개조 수술을 받고 스캐빈저로 흘러 들어갔다는 소문도 있다고.","JPN":"クモの奴らがばらばらになった後、裏切った組織員の大半は身体改造手術を受けてスカベンジャーに流れ着いたって噂があるんだ。","ENG":"There are rumors that after the Arachnids disbanded, the majority of the traitorous members underwent body modification and joined the Scavengers.","TWN":"蜘蛛瓦解之後，有傳言說大多數叛徒都接受了身體改造手術，加入了清道夫。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"스, 스캐빈저요? 그 미친 자식들이……?","JPN":"す、スカベンジャーですか？　あのイカれたやつらが……？","ENG":"S-Scavengers? Those lunatics...?","TWN":"清道夫？那些瘋子……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"아무튼 잘 알아두라고, 동생아.","JPN":"とにかく覚えておけよ。","ENG":"Anyway, just letting you know, little one.","TWN":"總之記住了，老弟。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"용병질 하면서 거미든, 스캐빈저든 잘못 엮이면 그대로 인생 쫑 나는 거야.","JPN":"傭兵やってて、クモとかスカベンジャーに絡まれたらそこでお終いだ。","ENG":"Once you get involved with the Arachinds or Scavengers while working as a mercenary, your life ends there.","TWN":"做我們雇傭兵這行，不管蜘蛛還是清道夫，一旦惹上了，人生就算完了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그 여자 눈 기억해? 얼굴은 반반하게 생겨가지고, 완전 살인자의 눈이었잖아.","JPN":"あの女の目、覚えてるか？　きれーな顔して殺人鬼の目してたろ。","ENG":"Do you remember that girl's eyes? She looked pretty cute, but her eyes were those of a killer's.","TWN":"還記得那個女人的眼睛嗎？雖然長得挺漂亮，但那完全是殺人的眼神。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"내가 거기서 넙죽 엎드리지 않았으면, 지금쯤……!","JPN":"あの場でひれ伏してなかったら今頃……！！","ENG":"If I didn't back down there, we'd all be–!","TWN":"如果我當時沒有識相趴下，現在……！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"살인자의 눈이라서 미안하네요.","JPN":"殺人鬼の目で悪かったですね。","ENG":"Sorry I have the eyes of a killer.","TWN":"抱歉，關於我有殺人的眼神。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"이래 봬도 최대한 착하게 떠 보려고 노력하고 있습니다만.","JPN":"私なりになるべく優しい目つきをするように努力していますが。","ENG":"Just know that I did try my best to look as gentle as possible.","TWN":"以防萬一你不知道，我已經儘量顯得友善了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"거, 거, 거, 거, 거미 누님……!?","JPN":"く、く、く、く、クモの姉貴……！？","ENG":"A-A-A-A-Arachnid lady...?!","TWN":"蜘、蜘、蜘、蜘、蛛……！?"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"아까 일행 분들과 함께 돌아가신 거 아니었습니까……!?","JPN":"連れの方々と帰られたのではなかったのですか……！？","ENG":"Didn't you head back with your friends...?!","TWN":"你你你！剛才不是和同伴們一起回去了嗎……？！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"전 개인적인 사정으로 여기 남기로 했어요.","JPN":"事情があって、ここに残ることにしました。","ENG":"I decided to stay here for personal reasons.","TWN":"因為個人原因，我決定留在這裡。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"아직 볼 일이 남았거든요.","JPN":"まだ用事が残っていましてね。","ENG":"I still have business here, you see.","TWN":"我還有事要處理。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그…… 볼 일이라고 하시면……?","JPN":"その……用事、というのは……？","ENG":"And... by business, you mean...?","TWN":"那……你說的事情是……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"호, 혹시 저희를……?","JPN":"ま、まさか俺たちを……？","ENG":"I-Is it us...?","TWN":"不會是我們吧……？……哈哈，哈哈哈！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"안심하세요. 어차피 당신들을 매달아 봤자 하나도 재미없을 테니까.","JPN":"安心してください。あなたたちを吊るしても何も楽しいことはありませんから。","ENG":"Rest assured. I won't find pleasure even if I hung you all.","TWN":"放心吧。反正把你們吊起來也沒什麼意思。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"하긴 그렇죠! 하, 하하!","JPN":"ですよね！　は、ははは！","ENG":"Right? Ha, haha!","TWN":"是啊！哈，哈哈！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그 대신…….","JPN":"その代わり……","ENG":"But instead...","TWN":"但是……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"당신들에게 한 가지 협조를 부탁드리고 싶습니다만.","JPN":"あなたたちに、一つ協力してもらいたいのです。","ENG":"I want to ask for your cooperation on something.","TWN":"我想請你們幫個忙。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"협조요? 저희가요?","JPN":"協力ですか？　俺たちに？","ENG":"Cooperation? Us?","TWN":"幫忙？我們！？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"안되나요?","JPN":"ダメですか？","ENG":"Is that a no?","TWN":"不行嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"……아, 아무렴요!","JPN":"……と、とんでもありません！","ENG":"...O-of course not!","TWN":"……當當當然可以！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"누님께서 부탁하시는데 도와드려야죠! 말씀만 해주세요!","JPN":"姉貴の頼みを断るわけないじゃないですか！　なんなりと仰ってください！","ENG":"We're thrilled to help you! Just say the word!","TWN":"大姊頭的請求，我們當然要幫！請儘管開口！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"최근 이곳에서 5종 침식체, 데모고르곤이 격퇴되었다는 소문을 들었어요.","JPN":"最近この場所で第5種侵食体、デモゴルゴンが撃退されたという噂を聞きました。","ENG":"I heard a rumor that a Category 5 Demogorgon was defeated here recently.","TWN":"我聽說有5類侵蝕體，魔神在這裡被擊退了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그리고 이곳 국경지대 어딘가 좌초된 그림자들의 함선이 방치되어 있다고 하더군요.","JPN":"そしてこの国境地帯のどこかに、座礁したシャドウたちの艦船が放置されているそうです。","ENG":"And that there is a ship of the Shadows stranded somewhere in the border.","TWN":"而且聽說有艘擱淺的暗影艦船被遺棄在了這片邊境的某個地方。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"저, 누님……?","JPN":"あの、姉貴……","ENG":"Uh, ma'am...?","TWN":"大姊頭，你……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그건 혹시 <color=#ffd34c>코러스</color>를 말씀하시는 걸까요……?","JPN":"それはもしかして、<color=#ffd34c>コーラス</color>のことですか……？","ENG":"Are you talking about <color=#ffd34c>Chorus</color> by chance...?","TWN":"你說的或許是那艘<color=#ffd34c>Chorus</color>嗎……?"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그래요. 그런 이름이었던 것 같네요.","JPN":"そうですね。そんな名前だった気がします。","ENG":"Yes. I think it was that kind of name.","TWN":"是，好像就是那個名字。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"자, 잠깐만요!","JPN":"ま、待ってください！","ENG":"G-give me a second!","TWN":"等，等一下！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L49_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"거긴 잔류 침식파가 워낙 강해서 못 들어가는데요?","JPN":"そこは残留侵食波が強すぎて入れませんって。","ENG":"That place has too strong Corruption ray residuals to enter.","TWN":"那裡殘留的侵蝕波太強了，我們是進不去的！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"게다가 지금 부품을 노리는 스캐빈저들이 들끓는다는 소문이…….","JPN":"それに今は部品を狙うスカベンジャーどもが湧きでてるし……","ENG":"Also, there are rumors about Scavengers crawling there looking for parts...","TWN":"而且現在有傳言說清道夫在覬覦那艘船……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"어라 스캐빈저? 설마, 누님……?","JPN":"って、スカベンジャー？　まさか……？","ENG":"Huh? Scavengers? Are you...?","TWN":"咦，清道夫？難道，大姊頭你……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"상관없어요. 당신들은 안내만 해주고 빠지세요.","JPN":"あなたたちは案内だけして帰って構わないです。","ENG":"It doesn’t matter. You just need to be my guide then get out.","TWN":"沒關係。你們只要帶我過去就可以。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"로스트 쉽 코러스에 진입하는 건, 저 한 사람이면 충분합니다.","JPN":"ロストシップコーラスに進入するのは、私一人で十分です。","ENG":"I'll be the only one getting on the Lost Ship Chorus.","TWN":"進入Chorus，只需要我一個人就夠了。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"이건 어디까지나 제 개인적인 사정이니까요.","JPN":"あくまで私個人の都合で行くだけなので。","ENG":"This is a personal matter, after all.","TWN":"這只是我私人的原因。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그, 그 말씀은……?","JPN":"そ、それはつまり……？","ENG":"Th-that means...","TWN":"那，那個，你的意思是……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"거미가 다시 스캐빈저를……?","JPN":"クモが、再びスカベンジャーを……？","ENG":"The Arachnids are going after the Scavengers…?","TWN":"蜘蛛要準備對清道夫下手了……？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};